mapper.select:
SELECT D.DRAW_ID , D.STORE_ID , S.STORE_NM , D.LOCATION_ID , L.LOCATION_NM , D.PRODUCT_ID , P.PRODUCT_NM , D.DRAW_NM , D.TOTAL_QTY , D.CURRENT_QTY , D.LIMIT_QTY , D.SALES_PRICE , D.ENTRY_START_DATE , D.ENTRY_END_DATE , D.DRAW_DATE , D.PICKUP_START_DATE , D.PICKUP_END_DATE , D.STATUS , D.DESCRIPTION FROM draw_mst D LEFT JOIN store_mst S ON D.STORE_ID = S.STORE_ID LEFT JOIN store_location_mst L ON D.LOCATION_ID = L.LOCATION_ID LEFT JOIN product_mst P ON D.PRODUCT_ID = P.PRODUCT_ID WHERE D.STORE_ID = #{storeId} AND D.LOCATION_ID = #{locationId}
AND D.STATUS = #{status}
AND D.DRAW_DATE >= #{startDate} AND D.DRAW_DATE < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
ORDER BY D.DRAW_DATE DESC

    	/* 티켓 번호 조회 쿼리 락도 같이 걸림 이거 조회해서 티켓 집어넣어서 이렇다 */
	    SELECT IFNULL(MAX(TICKET_NO), 0)
	    FROM draw_entry_ticket
	    WHERE DRAW_ID = #{drawId}
	    FOR UPDATE

        /* 랜덤 티켓 추첨 */
	    SELECT T.TICKET_NO
		FROM   draw_entry_ticket T
		JOIN   draw_entry_mst E
		  ON   T.DRAW_ENTRY_ID = E.DRAW_ENTRY_ID
		WHERE  T.DRAW_ID = #{drawId}
		  AND  E.ENTRY_STATUS = 'ENTRY'
		ORDER BY RAND()
		LIMIT #{winnerCnt}

	/** 당첨 조회 */
    SELECT DISTINCT DRAW_ENTRY_ID
    FROM   draw_entry_ticket
    WHERE  DRAW_ID = #{drawId}
      AND  TICKET_NO IN

          #{ticketNo}

mapper.update:
	/* 당첨  상태 업데이트 */
    UPDATE draw_entry_mst
    SET    ENTRY_STATUS = 'WIN'
    WHERE  DRAW_ID = #{drawId}
      AND  ENTRY_STATUS = 'ENTRY'
      AND  DRAW_ENTRY_ID IN

          #{id}

	/* 탈락  상태 업데이트 */
    UPDATE draw_entry_mst
    SET    ENTRY_STATUS = 'LOSE'
    WHERE  DRAW_ID = #{drawId}
      AND  ENTRY_STATUS = 'ENTRY'

mapper.select:
/* batch : 추첨 대상 드로우 조회 */ SELECT DRAW_ID FROM draw_mst WHERE STATUS = 'ENTRY'
AND DRAW_DATE < NOW()
FOR UPDATE SKIP LOCKED

mapper.update:
/* batch : 상태 ENTRY → DRAW */
UPDATE draw_mst
   SET STATUS      = 'DRAW'
     , UPDATE_DATE = NOW()
 WHERE DRAW_ID = #{drawId}
   AND STATUS = 'ENTRY'

mapper.select:
/* batch : 픽업 종료 대상 드로우 조회 */ SELECT DRAW_ID FROM draw_mst WHERE STATUS = 'DRAW'
AND PICKUP_END_DATE < NOW()
FOR UPDATE SKIP LOCKED

mapper.update:
/* 드로우 상태 DRAW → END */
UPDATE draw_mst
SET    STATUS      = 'END'
     , UPDATE_DATE = NOW()
WHERE  DRAW_ID = #{drawId}
  AND  STATUS  = 'DRAW'
